// Concatene tous les mails recus en un seul bloc texte pour Claude.
const items = $input.all();
if (items.length === 0) {
  return [{ json: { prompt: null, count: 0 } }];
}
const lignes = items.map((it, i) => {
  const m = it.json;
  const from = m.from?.value?.[0]?.address || m.from?.text || m.From || 'inconnu';
  const sujet = m.subject || m.Subject || '(sans objet)';
  const apercu = (m.snippet || m.textPlain || '').toString().slice(0, 300);
  return `${i + 1}. De: ${from}\n   Objet: ${sujet}\n   Apercu: ${apercu}`;
}).join('\n\n');
const prompt = `Tu es l'assistant matinal d'Alexis. Voici les mails recus dans les dernieres 24h. Redige un resume vocal court en francais, lu a voix haute par une enceinte : pas de markdown, pas de listes a puces, des phrases simples.\n\nNe retiens QUE ce qui compte vraiment : les messages ecrits par de vraies personnes qui s'adressent a lui (surtout ceux qui attendent une reponse) ; ce qui demande une action ou a une echeance (rdv, paiement, document a fournir, reponse attendue) ; les sujets pro, opportunites, contacts reseau, candidatures, clients ; l'argent (factures, paiements, banque, abonnements).\n\nIGNORE totalement, n'en parle pas du tout : les codes de securite ou 2FA et les notifications de connexion ; les newsletters, promotions et alertes emploi automatiques ; les accuses de reception et confirmations automatiques ; les notifications de reseaux sociaux.\n\nCommence par le nombre de mails vraiment importants (pas le total recu). Presente-les du plus important au moins important, en disant qui ecrit et ce qui est attendu de lui. Si rien n'est notable ce matin, dis-le simplement en une phrase, sans meubler.\n\nMails:\n${lignes}`;
return [{ json: { prompt, count: items.length } }];
